// Node 2 — Fetch axe-core rules from GitHub
// Step A: list rule files via GitHub contents API (1 call, well under 60/hr)
// Step B: fetch each rule's JSON from raw.githubusercontent.com (no rate limit on raw content)
// Step C: emit normalized items matching the merge node's expected shape

const AXE_VERSION = '4.10';

const listing = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.github.com/repos/dequelabs/axe-core/contents/lib/rules',
  headers: {
    'Accept': 'application/vnd.github.v3+json',
    'User-Agent': 'n8n-accessibility-monitor'
  },
  json: true,
});

const ruleFiles = (Array.isArray(listing) ? listing : [])
  .filter(f => f.type === 'file' && f.name.endsWith('.json'));

// Fetch rule contents in parallel batches to keep memory bounded
const CONCURRENCY = 12;
const out = [];
for (let i = 0; i < ruleFiles.length; i += CONCURRENCY) {
  const batch = ruleFiles.slice(i, i + CONCURRENCY);
  const fetched = await Promise.all(batch.map(async (f) => {
    try {
      const rule = await this.helpers.httpRequest({
        method: 'GET',
        url: f.download_url,
        json: true,
      });
      const meta = rule.metadata || {};
      const id = rule.id || f.name.replace(/\.json$/, '');
      return {
        id,
        description: meta.description || '',
        help: meta.help || '',
        helpUrl: `https://dequeuniversity.com/rules/axe/${AXE_VERSION}/${id}`,
        tags: rule.tags || [],
      };
    } catch (e) {
      return null;
    }
  }));
  out.push(...fetched.filter(x => x));
}

return out.map(r => ({ json: r }));

// Node 5 — Merge all sources, normalize to canonical schema, deduplicate, validate

const axeItems  = $('GitHub API — Axe-core Rules').all();
const wcagItems = $('W3C WCAG JSON — Success Criteria').all();
const rss1Items = $('RSS — WebAIM Blog').all();
const rss2Items = $('RSS — A11y Project').all();

const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

// Normalize axe-core rules
const axeRecords = axeItems.map(item => {
  const d = item.json;
  return {
    record_id: `axe_${d.id || d.name || 'unknown'}`,
    source: 'axe-core',
    type: 'rule',
    rule_id: d.id || d.name || '',
    wcag_criterion: (d.tags || []).find(t => /wcag\d{3}/.test(t))?.replace('wcag', '').replace(/(\d)(\d{2})/, '$1.$2') || '',
    conformance_level: (d.tags || []).includes('wcag2aa') || (d.tags || []).includes('wcag21aa') ? 'AA' : (d.tags || []).includes('wcag2a') ? 'A' : '',
    title: d.description || d.help || '',
    description: d.description || '',
    help_url: d.helpUrl || '',
    tags: (d.tags || []).join(', '),
    url: d.helpUrl || '',
    published_date: '',
    collected_at: today,
    quality: (d.description && d.id) ? 'complete' : 'incomplete'
  };
});

// Normalize WCAG success criteria
const wcagRecords = wcagItems.flatMap(item => {
  const data = item.json;
  // Handle both array and nested object formats from W3C JSON
  const criteria = Array.isArray(data) ? data : 
    (data.principles || []).flatMap(p => 
      (p.guidelines || []).flatMap(g => g.successcriteria || [])
    );
  return criteria.map(sc => ({
    record_id: `wcag_${sc.num || sc.id || 'unknown'}`,
    source: 'w3c-wcag',
    type: 'success_criterion',
    rule_id: '',
    wcag_criterion: sc.num || sc.id || '',
    conformance_level: sc.level || '',
    title: sc.handle || sc.title || '',
    description: sc.content || sc.description || '',
    help_url: sc.understanding || '',
    tags: `wcag21, level${(sc.level||'').toLowerCase()}`,
    url: sc.understanding || '',
    published_date: '',
    collected_at: today,
    quality: (sc.handle && sc.num) ? 'complete' : 'incomplete'
  }));
});

// Normalize RSS articles
const normalizeDate = (raw) => {
  if (!raw) return '';
  try {
    return new Date(raw).toISOString().split('T')[0];
  } catch { return ''; }
};

const rssRecords = [...rss1Items, ...rss2Items].map(item => {
  const d = item.json;
  const source = rss1Items.includes(item) ? 'webaim-blog' : 'a11y-project';
  const dateStr = normalizeDate(d.pubDate || d.date || d.isoDate || '');
  const dateKey = dateStr.replace(/-/g, '');
  return {
    record_id: `rss_${source}_${dateKey}_${(d.title||'').slice(0,20).replace(/\s+/g,'_').toLowerCase()}`,
    source,
    type: 'article',
    rule_id: '',
    wcag_criterion: '',
    conformance_level: '',
    title: d.title || '',
    description: d.contentSnippet || d.content || d.summary || '',
    help_url: '',
    tags: 'accessibility, industry-news',
    url: d.link || d.url || '',
    published_date: dateStr,
    collected_at: today,
    quality: (d.title && dateStr) ? 'complete' : 'incomplete'
  };
});

// Merge all records
const allRecords = [...axeRecords, ...wcagRecords, ...rssRecords];

// Deduplicate by record_id
const seen = new Set();
const unique = allRecords.filter(r => {
  if (seen.has(r.record_id)) return false;
  seen.add(r.record_id);
  return true;
});

// Return as n8n items
return unique.map(r => ({ json: r }));
